window.__QUIZ_DATA__=[{"id":"objective>Biology>2017>1","subject":"Biology","year":"2017","type":"Objective","topic":"CONCEPT OF LIVING : ORGANIZATION OF LIFE","question":"Which of the following groups of animals do not posses a nervous system?","images":[],"options":{"A":"Porifera","B":"Cnidaria","C":"Platyhelminthes","D":"Nematoda"},"answer":"A","explanation":"Porifera, also known as sponges, do not have a nervous system. They are simple multicellular organisms that lack true tissues and organs. They do not have a nervous system, digestive system, or circulatory system. Instead, they have specialized cells that perform different functions.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2017>2","subject":"Biology","year":"2017","type":"Objective","topic":"CONCEPT OF LIVING : FORMS IN WHICH LIVING CELLS EXIST","question":"The structural similarities in Paramecium and Euglena are in the","images":[],"options":{"A":"shape of locomotory organs","B":"blunt anterior and pointed posterior","C":"presence of micro and mega nuclei in both","D":"presence of anterior and posterior contractile vacuoles"},"answer":"B","explanation":"The structural similarities in Paramecium and Euglena is the blunt anterior and pointed posterior","marks":"1","difficulty":"2"},{"id":"objective>Biology>2017>3","subject":"Biology","year":"2017","type":"Objective","topic":"CONCEPT OF LIVING : FORMS IN WHICH LIVING CELLS EXIST","question":"Which of the following organisms cannot exist freely on its own?","images":[],"options":{"A":"Chlamydomonas","B":"Amoeba","C":"Paramecium","D":"Plasmodium"},"answer":"D","explanation":"Plasmodium is a genus of parasitic protozoans. They cannot exist freely on their own because they require a host to complete their life cycle. They are known to cause malaria in humans. The other options, Chlamydomonas, Amoeba, and Paramecium, are all free-living organisms.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2017>4","subject":"Biology","year":"2017","type":"Objective","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"The diagram below is an illustration of an Arthropod. Study it and answer this question      The Arthropod in the diagram is not an insect because it","images":["data:image/png;base64,"],"options":{"A":"has a big head which is almost equal to the \"thorax\"","B":"has eight legs and no wings","C":"does not have visible eyes on its head","D":"has head, thorax and abdomen"},"answer":"B","explanation":"the arthropods represented in the question has 8 legs while insect has sx legs","marks":"1","difficulty":"2"},{"id":"objective>Biology>2017>5","subject":"Biology","year":"2017","type":"Objective","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"Which of the following cell organelles is the site for the production of ATP?","images":[],"options":{"A":"Lysosome","B":"Nucleus","C":"Mitochondrion","D":"Ribosome"},"answer":"C","explanation":"The mitochondrion is the site for the production of ATP (Adenosine Triphosphate). ATP is often called the 'energy currency of the cell'. It is produced in the mitochondria through a process called cellular respiration, where glucose and oxygen are used to produce ATP, carbon dioxide, and water. The other options, Lysosome, Nucleus, and Ribosome, are not involved in ATP production.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2017>6","subject":"Biology","year":"2017","type":"Objective","topic":"CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT","question":"An example of osmosis in plants is the","images":[],"options":{"A":"movement of water through the xylem","B":"loss of water vapour from the stomata","C":"translocation of food through the phloem","D":"absorption of water from the soil by the root."},"answer":"D","explanation":"Osmosis is the process by which water molecules move from an area of high concentration to an area of low concentration through a semi-permeable membrane. In plants, this process is evident in the absorption of water from the soil by the root hairs. The water in the soil is at a higher concentration than the water in the root hairs, so it moves into the root hairs by osmosis.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2017>7","subject":"Biology","year":"2017","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : MODES OF NUTRITION","question":"The organism that can carry out both autotrophic and heterotrophic modes of nutrition is","images":[],"options":{"A":"Chlamydomonas","B":"Eudorina","C":"Euglena","D":"Spirogyra"},"answer":"C","explanation":"Euglena is a protist which has both plant-like features, e.g chloroplast, and animal-like features, e.g pellicle, hence, it can feed both autotrophically and heterotrophically.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2017>8","subject":"Biology","year":"2017","type":"Objective","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"The diagram below illustrates a part of the human skeleton. Study it and answer this question      The diagram represents the bones of the","images":["data:image/png;base64,"],"options":{"A":"upper arm","B":"lower arm","C":"upper leg","D":"lower leg"},"answer":"B","explanation":"The bone represented is the bone of the lower arm. Lower Arm (Radius and Ulna):Radius: Located on the lateral side of the forearm (thumb side), it is thicker near the wrist.Ulna: Located on the medial side of the forearm (pinky side), it is thicker near the elbow and has a distinctive olecranon process that forms the elbow joint.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2017>9","subject":"Biology","year":"2017","type":"Objective","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"The diagram below illustrates a part of the human skeleton. Study it and answer this question    Which of the labelled parts articulates with the head of the trochlea to form a hinge joint?","images":["data:image/png;base64,"],"options":{"A":"I","B":"II","C":"III","D":"IV"},"answer":"B","explanation":"II is the point of articulation with the trochlea that forms a hinge joint.  N.B: The trochlea is a structure resembling a pulley, typically in reference to the area connecting the upper and lower arm","marks":"1","difficulty":"2"},{"id":"objective>Biology>2017>10","subject":"Biology","year":"2017","type":"Objective","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"The diagram below illustrates a part of the human skeleton. Study it and answer this question    The labelled part that provides surface for the attachment of the triceps is","images":["data:image/png;base64,"],"options":{"A":"I","B":"II","C":"III","D":"IV"},"answer":"C","explanation":"The labelled part III provides surface for the attachment of the triceps","marks":"1","difficulty":"2"},{"id":"objective>Biology>2017>11","subject":"Biology","year":"2017","type":"Objective","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"The diagram below illustrates the transverse section of a","images":["data:image/png;base64,"],"options":{"A":"dicotyledonous root","B":"monocotyledonous root","C":"dicotyledonous stem","D":"monocotyledonous stem"},"answer":"C","explanation":"The diagram represented is that of a dicot stem.  It should be noted that, dicot stems have a circular arrangement of vascular tissues whereas the stems of monocots have vascular-tissues bundles scattered through out","marks":"1","difficulty":"2"},{"id":"objective>Biology>2017>12","subject":"Biology","year":"2017","type":"Objective","topic":"CONCEPT OF LIVING : RESPIRATORY SYSTEM","question":"Which of the following actions does not occur during exhalation in man?","images":[],"options":{"A":"Thoracic cavity decreases in volume","B":"Diaphragm flattens","C":"Ribs move down and in","D":"Air pressure increases in the thoracic cavity"},"answer":"B","explanation":"During exhalation, the diaphragm relaxes and moves upward, creating a dome shape. It does not flatten. The flattening of the diaphragm occurs during inhalation, not exhalation.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2017>13","subject":"Biology","year":"2017","type":"Objective","topic":"CONCEPT OF LIVING : EXCRETORY SYSTEMS","question":"The diagram below is an illustration of the urinary tubule in a mammal. Study it and answer this question      Which of the following substances is found in the part labelled II only?","images":["data:image/png;base64,"],"options":{"A":"Lipid","B":"Protein","C":"Salts","D":"Water"},"answer":"B","explanation":"The diagram illustrated in the question is the nephron, the functional unit of the kidney.  The part labelled II is the renal artery it contains only blood proteins.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2017>14","subject":"Biology","year":"2017","type":"Objective","topic":"CONCEPT OF LIVING : EXCRETORY SYSTEMS","question":"The diagram below is an illustration of the urinary tubule in a mammal. Study it and answer this question    The part which contains the lowest concentration of urea is labelled","images":["data:image/png;base64,"],"options":{"A":"I","B":"II","C":"III","D":"IV"},"answer":"A","explanation":"The part of the nephron which contains the lowest concentration of urea is the malphigian corpuscle (I)","marks":"1","difficulty":"2"},{"id":"objective>Biology>2017>15","subject":"Biology","year":"2017","type":"Objective","topic":"CONCEPT OF LIVING : EXCRETORY SYSTEMS","question":"The diagram below is an illustration of the urinary tubule in a mammal. Study it and answer this question    Which of the following substances is greater in concentration in the part labelled IV when compared to that of the part labelled I?","images":["data:image/png;base64,"],"options":{"A":"Lipid","B":"Glucose","C":"Urea","D":"Uric acid"},"answer":"C","explanation":"The concentration of urea is higher in the collecting tubule compared to the Malphigian corpusle","marks":"1","difficulty":"2"},{"id":"objective>Biology>2017>16","subject":"Biology","year":"2017","type":"Objective","topic":"CONCEPT OF LIVING : EXCRETORY SYSTEMS","question":"Deamination of amino acids in the liver produces","images":[],"options":{"A":"blood sugar","B":"glycogen","C":"bile","D":"urea"},"answer":"D","explanation":"The process of deamination occurs in the liver. It is a process of protein metabolism, where the amino group of one protein is removed. This removed amino group is either transferred to a keto acid to form new compound or conjugated with CO2 via the urea cycle to form UREA which is later excreted through the kidney.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2017>17","subject":"Biology","year":"2017","type":"Objective","topic":"CONCEPT OF LIVING : HORMONAL COORDINATION","question":"Which of the following glands also serves as an exocrine gland?","images":[],"options":{"A":"Ovary","B":"Pancreas","C":"Adrenal","D":"Thyroid"},"answer":"B","explanation":"The pancreas serves as both an endocrine and an exocrine gland. As an endocrine gland, it produces hormones such as insulin and glucagon, which are released into the blood to control blood sugar levels. As an exocrine gland, it produces digestive enzymes that are released into the small intestine to aid in digestion.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2017>18","subject":"Biology","year":"2017","type":"Objective","topic":"CONCEPT OF LIVING : NERVOUS COORDINATION","question":"Which of the following sequences is the correct route of the transmission of impulses along a reflex arc?","images":[],"options":{"A":"Receptor \u2192 sensory neurone \u2192 synapse\u2192  intermediate neurone \u2192 synapse \u2192 motor neurone \u2192 effector","B":"Receptor \u2192 motor neurone \u2192 synapse \u2192 intermediate neurone \u2192 synapse \u2192 sensory neurone \u2192 effector","C":"Effector \u2192 intermediate neurone \u2192 synapse \u2192 motor neurone \u2192 synapse \u2192 sensory neurone \u2192 receptor","D":"Effector \u2192 motor neurone \u2192 synapse \u2192 sensory neurone \u2192 synapse \u2192 intermediate neurone \u2192 receptor"},"answer":"A","explanation":"The transmission of impulses along a reflex can be represented as   Receptor  \u2193  Sensory Neurone  \u2193  Synapse intermediate neurone  \u2193  Synapse  \u2193  Motor neurone effector","marks":"1","difficulty":"2"},{"id":"objective>Biology>2017>19","subject":"Biology","year":"2017","type":"Objective","topic":"CONCEPT OF LIVING : SENSE ORGANS","question":"When viewing an object that is close to the human eye, the","images":[],"options":{"A":"eye lens becomes thin","B":"ciliary muscles relax","C":"suspensory ligaments become taut","D":"eye lens become fat"},"answer":"D","explanation":"When viewing an object that is close to the human eye, the eye lens becomes fat. This is because the ciliary muscles contract, which reduces the tension on the suspensory ligaments holding the lens in place. This allows the lens to become more convex (or 'fatter') to increase its refractive power and focus on the close object. This process is known as accommodation.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2017>20","subject":"Biology","year":"2017","type":"Objective","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"The diagram below is an illustration of the human sperm. Study it and answer this question.      The part labelled I is the","images":["data:image/png;base64,"],"options":{"A":"acrosome","B":"nucleus","C":"mitochondrion","D":"tail"},"answer":"A","explanation":"The part labelled I is the acrosome. It is the pointed part of the \"head\" of the spermatozoan.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2017>21","subject":"Biology","year":"2017","type":"Objective","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"The diagram below is an illustration of the human sperm. Study it and answer this question.    The function of the part labelled II is to","images":["data:image/png;base64,"],"options":{"A":"fuse with the ovum during fertilization","B":"generate the energy for the sperm to swim to the fallopian tube","C":"help the sperm to swim forward","D":"dissolve the membrane of the egg during fertilization"},"answer":"C","explanation":"The part labelled II is the tail. Its function is to propel (swim) the spermatozoon forward.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2017>22","subject":"Biology","year":"2017","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"Which of the following types of placentation is not common amongst synacarpous pistils?","images":[],"options":{"A":"Marginal","B":"Axile","C":"Parietal","D":"Free central"},"answer":"B","explanation":"Axile placentation is not common amongst syncarpous pistil  In axile placentation ovules are borne at or around the center of a compound ovary or an axis from joined speta. This kind of placentation is not found in syncarpous ovaries in which carpets are fused by their stigmas but possess distinct ovaries","marks":"1","difficulty":"2"},{"id":"objective>Biology>2017>23","subject":"Biology","year":"2017","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"The complex energy-rich organic matter which living organisms need for life is","images":[],"options":{"A":"water","B":"air","C":"food","D":"mineral salts"},"answer":"C","explanation":"The complex energy-rich organic matter which living organisms need for life is food. Food provides the energy and nutrients that organisms need to be alive and healthy. It contains macronutrients like carbohydrates, proteins, and fats which are used for energy and growth, and micronutrients like vitamins and minerals which are needed in smaller amounts but are still essential for function and health.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2017>24","subject":"Biology","year":"2017","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"Which of the following processes are associated with photosynthesis?  I. Energy from sunlight is absorbed   II. Carbon dioxide is evolved  III. Oxygen is given off  IV. Glucose is synthesized","images":[],"options":{"A":"I and II only","B":"I, II and IV only","C":"I, III and IV only","D":"I, II, III and IV"},"answer":"C","explanation":"During the process of photosynthesis.  - Energy from sunlight is absorbed  - Oxygen is given off as by-product  - Glucose is synthesized  I, III and IV are processed associated with photosynthesis.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2017>25","subject":"Biology","year":"2017","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"Which of the following functions is associated with calcium in plants? Formation of","images":[],"options":{"A":"cell wall","B":"ribosomes","C":"proteins","D":"cell membrane"},"answer":"A","explanation":"Calcium plays a crucial role in the formation of the cell wall in plants. It is a part of the middle lamella, which is the layer between the primary walls of adjacent cells. It helps in the formation of calcium pectate, which provides rigidity to the cell wall.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2017>26","subject":"Biology","year":"2017","type":"Objective","topic":"CONCEPT OF LIVING : FORMS IN WHICH LIVING CELLS EXIST","question":"The diagrams below are illustrations of the dentition of an organism. Study them and answer this question.      The dentition belongs to a","images":["data:image/png;base64,"],"options":{"A":"rabbit","B":"cat","C":"frog","D":"man"},"answer":"D","explanation":"The dental formula represented in the question is :  I &nbsp C &nbsp P &nbsp& M  2 : 1 : 2 : 3  Hence, the dentition is for man","marks":"1","difficulty":"2"},{"id":"objective>Biology>2017>27","subject":"Biology","year":"2017","type":"Objective","topic":"CONCEPT OF LIVING : FORMS IN WHICH LIVING CELLS EXIST","question":"The diagrams below are illustrations of the dentition of an organism. Study them and answer this question.    The function of the teeth labelled X is for","images":["data:image/png;base64,"],"options":{"A":"biting and grasping","B":"chewing and grinding","C":"tearing and grasping","D":"chewing and tearing"},"answer":"C","explanation":"X is the canine. The teeth labelled X are pointed and located next to the incisors, which are characteristics of canines. Canines are primarily used for tearing and grasping food.Therefore, the function of the teeth labelled X is: Tearing and grasping.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2017>28","subject":"Biology","year":"2017","type":"Objective","topic":"CONCEPT OF LIVING : FORMS IN WHICH LIVING CELLS EXIST","question":"The diagrams below are illustrations of the dentition of an organism. Study them and answer this question.    The teeth which are absent in the young of the organism are labelled","images":["data:image/png;base64,"],"options":{"A":"W","B":"X","C":"Y","D":"Z"},"answer":"D","explanation":"Young man (children) lack molar in their dentition","marks":"1","difficulty":"2"},{"id":"objective>Biology>2017>29","subject":"Biology","year":"2017","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : POPULATION STUDIES BY SAMPLING","question":"The number of individuals that the environment can support over a long period of time is its","images":[],"options":{"A":"growth rate","B":"total capacity","C":"population capacity","D":"carrying capacity"},"answer":"D","explanation":"The carrying capacity of an environment is the maximum population size of a biological species that can be sustained over a long period of time given the availability of resources. It is a concept in population biology, which examines the dynamics of species populations.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2017>30","subject":"Biology","year":"2017","type":"Objective","topic":"ECOLOGY OF POPULATION : ECOLOGICAL SUCCESSION","question":"A good site for secondary succession would be","images":[],"options":{"A":"a sand dune","B":"a bare rock","C":"a land that has just has forest fire","D":"a stretch of barren land"},"answer":"C","explanation":"A good site for secondary session would be a land that has just had forest fire.  N.B: Secondary succession is the ecological succession that occurs after the initial succession has been disrupted and some plants and animals still exist. It is usually faster than secondary succession as:  1. Soil is already present  2. There are still some remnants of seeds, roots and underground vegetative organs of plants.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2017>31","subject":"Biology","year":"2017","type":"Objective","topic":"ECOLOGY OF POPULATION : FACTORS THAT AFFECT POPULATION","question":"A population which exceeds its carrying capacity and then collapses is represented graphically by a","images":[],"options":{"A":"bell-shaped curve","B":"linear curve","C":"sigmoid curve","D":"skewed curve"},"answer":"A","explanation":"A population which exceeds its carrying capacity and then collapses is represented graphically by a bell-shaped curve. This is because the population grows rapidly at first, then slows as it approaches the carrying capacity of the environment (the maximum population size that the environment can sustain indefinitely). Once the population exceeds the carrying capacity, it collapses, leading to a rapid decrease in population size. This creates a bell-shaped curve when graphed.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2017>32","subject":"Biology","year":"2017","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"The natural dwelling place of an organism is called its","images":[],"options":{"A":"ecological niche","B":"habitat","C":"population","D":"environment"},"answer":"B","explanation":"The natural dwelling place of an organism is referred to as its 'habitat'. This is the place where an organism lives and grows under natural conditions. An 'ecological niche' refers to the role and position a species has in its environment; how it meets its needs for food and shelter, how it survives, and how it reproduces. A 'population' refers to a group of individuals of the same species living in a specific geographical area and 'environment' refers to the surroundings or conditions in which a person, animal, or plant lives or operates.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2017>33","subject":"Biology","year":"2017","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS","question":"Which of the following ecological factors will result in food shortage?","images":[],"options":{"A":"Drought","B":"Low rate of reproduction","C":"Emigration","D":"Topography"},"answer":"A","explanation":"Drought is an ecological factor that can result in food shortage. Drought conditions mean less water availability for plants, which can lead to reduced plant growth and productivity, and subsequently less food availability for herbivores and omnivores. 'Low rate of reproduction' could potentially lead to a decrease in population size, but not necessarily a food shortage. 'Emigration' refers to the act of leaving one's own habitat to move to another, which could potentially affect food availability in the new habitat, but it's not a direct cause of food shortage. 'Topography' refers to the physical features of land, including its shapes and contours, and while it can influence where organisms live and what food sources are available, it's not a direct cause of food shortage.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2017>34","subject":"Biology","year":"2017","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : SIMPLE MEASUREMENT OF ECOLOGICAL FACTORS","question":"Soil permeability refers to","images":[],"options":{"A":"how easily water passes through the soil","B":"the proportion of air in the soil","C":"the proportion of water the soil holds","D":"how well water rises up the soil"},"answer":"A","explanation":"Soil permeability refers to the ability of the soil to allow water to pass through it. This is determined by the size and connectivity of the pore spaces in the soil. Larger and more connected pore spaces increase the soil's permeability.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2017>35","subject":"Biology","year":"2017","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : MODES OF NUTRITION","question":"Which of the following groups of organisms do not have members that can be called autotrophs?","images":[],"options":{"A":"Protists","B":"Mosses","C":"Chlorophyta","D":"Fungi"},"answer":"D","explanation":"Autotrophs are organisms that can produce their own food from inorganic substances, using light or chemical energy. Fungi are not autotrophs, they are heterotrophs, meaning they obtain their food from other organisms. Protists, Mosses, and Chlorophyta all have members that can be called autotrophs.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2017>36","subject":"Biology","year":"2017","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ENERGY TRANSFORMATION IN NATURE","question":"Which of the following pyramids gives the most accurate picture of the relationships between the organisms at the various trophic levels in a food chain? A pyramid of","images":[],"options":{"A":"numbers","B":"energy","C":"biomass","D":"size"},"answer":"B","explanation":"A pyramid of energy gives the most accurate picture of the relationships between the organisms at the various trophic levels in a food chain. This is because it takes into account not only the number of organisms at each level, but also the amount of energy they have stored, which is a more direct measure of their role in the ecosystem. The energy pyramid shows the decreasing amounts of energy at each higher trophic level, reflecting the energy loss from metabolic processes like respiration, growth and reproduction.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2017>37","subject":"Biology","year":"2017","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ENERGY TRANSFORMATION IN NATURE","question":"Which of the following statements is not associated with pyramids of energy?","images":[],"options":{"A":"Efficiency of energy transfer between trophic levels can be studied","B":"Comparisons of pyramids for different ecosystems can be made","C":"More accurate comparisons of trophic levels","D":"Representation of numbers of organisms at different trophic levels"},"answer":"D","explanation":"This statement is associated with pyramids of numbers, not pyramids of energy. Pyramids of energy represent the flow of energy through trophic levels, not the number of organisms.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2017>38","subject":"Biology","year":"2017","type":"Objective","topic":"CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION","question":"Which of the following materials is not easily biodegradable?","images":[],"options":{"A":"Polythene bag","B":"Cotton bag","C":"Hides and skin bag","D":"Paper bag"},"answer":"A","explanation":"Biodegradable materials are those that can be broken down by natural processes, such as the action of bacteria, fungi, and other decomposers. Polythene bags are made from petroleum products and are not easily broken down by these natural processes, making them non-biodegradable. On the other hand, cotton bags, hides and skin bags, and paper bags are all made from natural materials that can be broken down by decomposers, making them biodegradable.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2017>39","subject":"Biology","year":"2017","type":"Objective","topic":"ECOLOGICAL MANAGEMENT : BIOLOGICAL ASSOCIATIONS","question":"Which of the following pairs of organisms is in a mutualistic relationship?","images":[],"options":{"A":"Hydra and Sea anemone","B":"Hermit crab and Sea anemone","C":"Dodder plant and Cocoa Plant","D":"Mistletoe and Kolanut"},"answer":"B","explanation":"A mutualistic relationship is one in which both organisms benefit. In the case of the hermit crab and the sea anemone, the hermit crab uses the sea anemone for protection, while the sea anemone gets a free ride and access to more food. The other pairs listed do not have mutualistic relationships. The hydra and sea anemone do not interact in a way that benefits both, while the dodder plant and cocoa plant, and the mistletoe and kolanut, are examples of parasitic relationships, where one organism benefits at the expense of the other.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2017>40","subject":"Biology","year":"2017","type":"Objective","topic":"CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS","question":"The establishment of game reserves and parks is a method of","images":[],"options":{"A":"conserving natural resources","B":"cultivating game","C":"controlling pollution","D":"cultural awareness"},"answer":"A","explanation":"The establishment of game reserves and parks is a method of conserving natural resources. Game reserves and parks are protected areas where wildlife can live and breed without threat from hunting or habitat destruction. This helps to maintain biodiversity and conserve natural resources.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2017>41","subject":"Biology","year":"2017","type":"Objective","topic":"CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS","question":"Which of the following practices is not used in conserving water?","images":[],"options":{"A":"Afforestation","B":"Damming","C":"Deforestation","D":"Reforestation"},"answer":"C","explanation":"Deforestation is not a practice used in conserving water. In fact, it is the opposite. Deforestation involves the removal of trees which play a crucial role in the water cycle. Trees absorb water from the soil and release it into the atmosphere through a process called transpiration. When trees are removed, this process is disrupted leading to less moisture being released into the atmosphere and potentially less rainfall. The other options, afforestation, damming, and reforestation, are all practices that help in water conservation.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2017>42","subject":"Biology","year":"2017","type":"Objective","topic":"CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS","question":"Which of the following resources cannot be renewed?","images":[],"options":{"A":"Air","B":"Petroleum","C":"Food crop","D":"Soil"},"answer":"B","explanation":"Renewable resources are those that can be replenished naturally in the course of time. Air, food crops, and soil are renewable resources because they can be naturally replenished. Petroleum, on the other hand, is a non-renewable resource because it takes millions of years to form from the remains of plants and animals. Once we have used up all the petroleum, we cannot get more in a human timescale.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2017>43","subject":"Biology","year":"2017","type":"Objective","topic":"VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS","question":"Use the diagram below to answer this question      The type of variation illustrated above is","images":["data:image/png;base64,"],"options":{"A":"continuous variation","B":"discontinuous variation","C":"morphological variation","D":"environmental variation"},"answer":"B","explanation":"Rolling of the tongue is considered a discontinuous variation because it is a trait that is clearly distinct and is controlled by a single gene with two alleles. Discontinuous variation refers to traits that do not show a range or spectrum but instead are characterized by distinct, separate categories. Individuals can either roll their tongue or cannot, with no intermediate forms.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2017>44","subject":"Biology","year":"2017","type":"Objective","topic":"VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS","question":"Which of the following characters is not a morphological variation?","images":[],"options":{"A":"Shaper of the nose","B":"Colour of skin","C":"Colour of hair","D":"Tongue rolling"},"answer":"D","explanation":"Morphological variations refer to the physical differences between individuals of the same species. These can include differences in size, shape, and color. The shape of the nose, color of skin, and color of hair are all examples of morphological variations. Tongue rolling, however, is not a morphological variation. It is a genetic trait that is inherited from parents. It does not involve any physical differences in the structure or appearance of the body.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2017>45","subject":"Biology","year":"2017","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS","question":"An apple plant can produce sexually and asexually and it has 40 chromosomes in its leaf cells. How many chromosomes would be in each gamete and somatic cell?","images":[],"options":{"A":"20 chromosomes in the gametes and 10 in the somatic cells","B":"40 chromosomes in the gametes and 20 in the somatic cells","C":"20 chromosomes in the gametes and 40 in the somatic cells","D":"40 chromosomes in the gametes and 40 in the somatic cells"},"answer":"C","explanation":"The number of chromosomes in the gamete is usually half of the total chromosomes, and that in the somatic cell is usually equal to that in the cell.  Hence, there are 20 chromosomes in the gamete and 40 chromosomes in the somatic cell.","marks":"1","difficulty":"3"},{"id":"objective>Biology>2017>46","subject":"Biology","year":"2017","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"Assuming that A is the gene for normal skin colour and is dominant, while a is the gene for albinism and is recessive, what is the likely genotype of the couple which had 50% normal and 50% albino offspring?","images":[],"options":{"A":"AA, aa","B":"Aa, aa","C":"AA, Aa","D":"Aa, Aa"},"answer":"B","explanation":"The most likely genotypes of the parent that could result in 50% normal and 50% albino offsping are:  Aa aa  Proof:    Phenotypic ratio:   1 &nbsp &nbsp : &nbsp &nbsp  1  50% 50%","marks":"1","difficulty":"2"},{"id":"objective>Biology>2017>47","subject":"Biology","year":"2017","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"Which of the following statements is true about mutation?","images":[],"options":{"A":"Phenotype is not involved","B":"Genotype is not involved","C":"Artificial induction is not possible","D":"Genotype is involved"},"answer":"D","explanation":"Mutation is a change in the DNA sequence of a gene. This change can affect the genotype (the genetic makeup of an organism) and potentially the phenotype (the physical and physiological traits of an organism). Therefore, the statement 'Genotype is involved' is true about mutation. Artificial induction of mutation is also possible, for example, by exposure to radiation or certain chemicals.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2017>48","subject":"Biology","year":"2017","type":"Objective","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"One of the structural adaptations of mammals for movement on land is the development of the","images":[],"options":{"A":"hollow bones","B":"pentadactyl limb","C":"fused thoracic bones","D":"streamlined body"},"answer":"B","explanation":"Mammals have developed the pentadactyl limb for movement on land. The pentadactyl limb is a limb with five digits, like a human hand or foot, that is found in most mammals. This structure allows for a wide range of movement and flexibility, enabling mammals to adapt to different environments and modes of locomotion, such as running, climbing, swimming, or flying.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2017>49","subject":"Biology","year":"2017","type":"Objective","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"Which of the following traits is not characteristic of social insects?","images":[],"options":{"A":"All members are identical","B":"There is division of labour","C":"The members dwell in the same habitat","D":"Some members protect the queen"},"answer":"A","explanation":"In social insects, all members are not identical. There is usually a division of labor among different types of individuals (castes), such as workers, soldiers, and reproductive individuals (queens and males). Each caste has a different appearance and role within the colony. Therefore, the statement 'All members are identical' is not characteristic of social insects.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2017>50","subject":"Biology","year":"2017","type":"Objective","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"The gradual cumulative, adaptive and heritable changes in an organism over a long period of time resulting in new species is called","images":[],"options":{"A":"adaptation","B":"survival","C":"organic evolution","D":"interspecific competition"},"answer":"C","explanation":"The gradual cummulative, adaptive and inheritable changes in an organism over a long period of time resulting in new species is termed ORGANIC EVOLUTION  N.B: EVOLUTION means CHANGES","marks":"1","difficulty":"2"}];